package listeners;
import com.aventstack.extentreports.*;import org.testng.*;import reporting.*;import utils.ScreenshotUtil;
public class TestListener implements ITestListener, ISuiteListener { public void onTestStart(ITestResult r){ ExtentTest t=ExtentManager.get().createTest(r.getMethod().getMethodName()).assignCategory(r.getMethod().getGroups()); ExtentTestManager.set(t); t.info("Started: "+r.getStartMillis()); } public void onTestSuccess(ITestResult r){ ExtentTestManager.get().pass("Passed"); } public void onTestFailure(ITestResult r){ String path=ScreenshotUtil.takeFullPageScreenshot(r.getMethod().getMethodName()); ExtentTestManager.get().fail(r.getThrowable()).addScreenCaptureFromPath(path); } public void onTestSkipped(ITestResult r){ ExtentTestManager.get().skip(r.getThrowable()); } public void onFinish(ITestContext c){ ExtentTestManager.remove(); } public void onFinish(ISuite suite){ ExtentManager.flush(); } }
